DB_PATH = os.path.join(os.path.dirname(__file__), "..", "the-c-list.db")
db = sqlite3.connect(DB_PATH)

set_id = db.execute(
    "SELECT id FROM sets WHERE name = '2025 Topps Chrome Football'"
).fetchone()[0]
print(f"Updating set ID: {set_id}")

def odds(h, fdi, j, bd, sap, vse, vea, vcee, mse, mea, mcee, hse, hea, fan):
    keys = ['hobby','fdi','jumbo','breakers_delight','sapphire',
            'value_se','value_ea','value_cee',
            'mega_se','mega_ea','mega_cee',
            'hanger_se','hanger_ea','fanatics']
    vals = [h, fdi, j, bd, sap, vse, vea, vcee, mse, mea, mcee, hse, hea, fan]
    return {k: v for k, v in zip(keys, vals) if v != '-'}

