print(f"Total odds entries: {len(pack_odds)}")

# Restructure from {card_name: {box: odds}} to {box: {card_name: odds}}
restructured = {}
for card_name, box_odds in pack_odds.items():
    for box_key, odd_val in box_odds.items():
        if box_key not in restructured:
            restructured[box_key] = {}
        restructured[box_key][card_name] = odd_val

print("Box keys in new odds:")
for k, v in restructured.items():
    print(f"  {k}: {len(v)} entries")

db.execute(
    "UPDATE sets SET pack_odds = ? WHERE id = ?",
    (json.dumps(restructured), set_id)
)
db.commit()
print(f"\npack_odds updated for set ID {set_id}")
db.close()
